22	/// The value returned from a compare-and-swap operation.
23	pub struct CompareExchangeValue<'g, T: ?Sized + Pointable> {
24	    /// The previous value that was in the atomic pointer.
25	    pub old: Shared<'g, T>,
26	
27	    /// The new value that was stored.
28	    pub new: Shared<'g, T>,
29	}
