31	impl<T: ?Sized + Pointable> fmt::Debug for CompareExchangeValue<'_, T> {
32	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
33	        f.debug_struct("CompareExchangeValue")
34	            .field("old", &self.old)
35	            .field("new", &self.new)
36	            .finish()
37	    }
38	}
