40	/// The error returned on failed compare-and-swap operation.
41	pub struct CompareExchangeError<'g, T: ?Sized + Pointable, P: Pointer<T>> {
42	    /// The value in the atomic pointer at the time of the failed operation.
43	    pub current: Shared<'g, T>,
44	
45	    /// The new value, which the operation failed to store.
46	    pub new: P,
47	}
