49	impl<T, P: Pointer<T> + fmt::Debug> fmt::Debug for CompareExchangeError<'_, T, P> {
50	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
51	        f.debug_struct("CompareExchangeError")
52	            .field("current", &self.current)
53	            .field("new", &self.new)
