58	/// Returns a bitmask containing the unused least significant bits of an aligned pointer to `T`.
59	#[inline]
60	fn low_bits<T: ?Sized + Pointable>() -> usize {
61	    (1 << T::ALIGN.trailing_zeros()) - 1
62	}
63	
64	/// Panics if the pointer is not properly unaligned.
65	#[inline]
66	fn ensure_aligned<T: ?Sized + Pointable>(raw: *mut ()) {
67	    assert_eq!(raw as usize & low_bits::<T>(), 0, "unaligned pointer");
68	}
69	
70	/// Given a tagged pointer `data`, returns the same pointer, but tagged with `tag`.
71	///
72	/// `tag` is truncated to fit into the unused bits of the pointer to `T`.
73	#[inline]
74	fn compose_tag<T: ?Sized + Pointable>(ptr: *mut (), tag: usize) -> *mut () {
75	    map_addr(ptr, |a| (a & !low_bits::<T>()) | (tag & low_bits::<T>()))
76	}
77	
78	/// Decomposes a tagged pointer `data` into the pointer and the tag.
79	#[inline]
80	fn decompose_tag<T: ?Sized + Pointable>(ptr: *mut ()) -> (*mut (), usize) {
81	    (
82	        map_addr(ptr, |a| a & !low_bits::<T>()),
83	        ptr as usize & low_bits::<T>(),
84	    )
85	}
86	
87	// FIXME: This is exactly <https://doc.rust-lang.org/nightly/std/primitive.pointer.html#method.map_addr-1>,
88	// which we cannot use yet due to the MSRV.
89	#[inline]
90	fn map_addr<T>(ptr: *mut T, f: impl FnOnce(usize) -> usize) -> *mut T {
91	    let new_addr = f(ptr as usize);
92	    ptr.cast::<u8>()
93	        .wrapping_add(new_addr.wrapping_sub(ptr as usize))
94	        .cast::<T>()
95	}
